mapper.select:
SELECT COUNT(1)
FROM news_text_segment
WHERE news_id = #{newsId}

SELECT nts.news_id AS newsId, nts.chunk_index AS chunkIndex, nts.content AS content, nts.embedding AS embedding, n.title AS title, n.pub_date AS pubDate, n.url AS url FROM news_text_segment nts JOIN news_data n ON n.id = nts.news_id WHERE (n.deleted = 0 OR n.deleted IS NULL)
AND n.pub_date >= #{start}
AND n.pub_date <= #{end}
ORDER BY n.pub_date DESC, nts.news_id DESC, nts.chunk_index ASC LIMIT #{limit}

SELECT n.id
FROM news_data n
WHERE (n.deleted = 0 OR n.deleted IS NULL)

    AND n.pub_date >= #{start}


    AND n.pub_date <= #{end}

ORDER BY n.pub_date DESC, n.id DESC
LIMIT #{limit}
